<?php
$now=time();$groups=['active'=>[],'used'=>[],'expired'=>[]];
foreach($coupons as $coupon){$expired=!$coupon['is_active']||($coupon['ends_at']&&strtotime($coupon['ends_at'])<$now)||($coupon['max_uses']!==null&&(int)$coupon['used_total']>=(int)$coupon['max_uses']);$used=(int)$coupon['used_by_user']>0;$groups[$used?'used':($expired?'expired':'active')][]=$coupon;}
$labels=['active'=>'Active','used'=>'Utilizate','expired'=>'Expirate'];
?>
<section class="account-page shell section-space-small"><div class="account-head"><p class="eyebrow">AVANTAJELE TALE</p><h1>Cupoane</h1><p>Vezi codurile disponibile și condițiile lor înainte de checkout.</p></div><div class="account-layout"><?php require BASE_PATH.'/app/Views/account/nav.php'; ?><div class="account-content coupon-wallet">
<?php foreach($groups as $key=>$items): ?><section class="account-panel"><div class="panel-head"><h2><?= e($labels[$key]) ?></h2><span class="coupon-group-count"><?= count($items) ?></span></div><?php if(!$items): ?><p class="empty-copy">Nu există cupoane în această secțiune.</p><?php else: ?><div class="customer-coupon-grid"><?php foreach($items as $coupon): ?><article class="customer-coupon-card coupon-<?= e($key) ?>"><div><span><?= $coupon['discount_type']==='percent'?(int)$coupon['discount_value'].'%':money($coupon['discount_value']) ?></span><strong><?= e($coupon['code']) ?></strong></div><ul><li>Comandă minimă: <?= money($coupon['minimum_order_minor']) ?></li><?php if($coupon['category_names']): ?><li><?= e($coupon['category_names']) ?></li><?php endif; ?><?php if($coupon['product_names']): ?><li><?= e($coupon['product_names']) ?></li><?php endif; ?><?php if($coupon['max_uses_per_user']): ?><li>Maximum <?= (int)$coupon['max_uses_per_user'] ?> utilizări / client</li><?php endif; ?></ul><?php if($key==='active'&&$coupon['ends_at']): ?><div class="coupon-countdown" data-coupon-countdown="<?= e(date(DATE_ATOM,strtotime($coupon['ends_at']))) ?>"><small>Expiră în</small><strong data-countdown-value>—</strong></div><?php elseif($coupon['ends_at']): ?><small>Valabil până la <?= e(date('d.m.Y H:i',strtotime($coupon['ends_at']))) ?></small><?php endif; ?></article><?php endforeach; ?></div><?php endif; ?></section><?php endforeach; ?>
</div></div></section>